import{_ as t,c as o,o as n,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse(`{"title":"Context Injection: Give Agents Foresight | opencode-supermemory","description":"Learn about automatic context injection in opencode-supermemory. Understand how agents acquire user profiles and project knowledge at the start of a session, and master keyword-triggered memory saving.","frontmatter":{"title":"Context Injection: Give Agents Foresight | opencode-supermemory","sidebarTitle":"Context Injection","subtitle":"Automatic Context Injection: Giving Agents 'Foresight'","description":"Learn about automatic context injection in opencode-supermemory. Understand how agents acquire user profiles and project knowledge at the start of a session, and master keyword-triggered memory saving.","tags":["context","injection","prompt","memory"],"prerequisite":["start-getting-started"],"order":999},"headers":[],"relativePath":"supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"supermemoryai/opencode-supermemory/core/context-injection/index.md"}`),a={name:"supermemoryai/opencode-supermemory/core/context-injection/index.md"};function i(r,e,l,c,d,h){return n(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="automatic-context-injection-giving-agents-foresight" tabindex="-1">Automatic Context Injection: Giving Agents &quot;Foresight&quot; <a class="header-anchor" href="#automatic-context-injection-giving-agents-foresight" aria-label="Permalink to &quot;Automatic Context Injection: Giving Agents &quot;Foresight&quot;&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>By the end of this lesson, you will be able to:</p><ol><li><strong>Understand</strong> why the Agent knows your coding habits and project architecture from the very beginning.</li><li><strong>Master</strong> the &quot;3D Model&quot; of context injection (User Profile, Project Knowledge, Relevant Memories).</li><li><strong>Learn</strong> to use keywords (like &quot;Remember this&quot;) to actively intervene in the Agent&#39;s memory behavior.</li><li><strong>Configure</strong> the number of injected items to balance context length with information richness.</li></ol><hr><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>Before memory plugins, every time you started a new session, the Agent was a blank slate. You had to repeatedly tell it: &quot;I use TypeScript,&quot; &quot;This project uses Next.js.&quot;</p><p><strong>Context Injection</strong> solves this problem. It&#39;s like slipping a &quot;mission briefing&quot; into the Agent&#39;s mind the moment it wakes up.</p><h3 id="trigger-timing" tabindex="-1">Trigger Timing <a class="header-anchor" href="#trigger-timing" aria-label="Permalink to &quot;Trigger Timing&quot;">​</a></h3><p>opencode-supermemory is extremely restrained, triggering automatic injection only on the <strong>first message of the session</strong>.</p><ul><li><strong>Why only the first?</strong> Because this is the critical moment to establish the session&#39;s tone.</li><li><strong>What about subsequent messages?</strong> Subsequent messages are not automatically injected to avoid disrupting the flow of conversation, unless you actively trigger it (see &quot;Keyword Trigger&quot; below).</li></ul><h3 id="the-3d-injection-model" tabindex="-1">The 3D Injection Model <a class="header-anchor" href="#the-3d-injection-model" aria-label="Permalink to &quot;The 3D Injection Model&quot;">​</a></h3><p>The plugin fetches three types of data in parallel and combines them into a <code>[SUPERMEMORY]</code> prompt block:</p><table tabindex="0"><thead><tr><th>Data Dimension</th><th>Source</th><th>Function</th><th>Example</th></tr></thead><tbody><tr><td><strong>1. User Profile</strong> (Profile)</td><td><code>getProfile</code></td><td>Your long-term preferences</td><td>&quot;User likes functional programming&quot;, &quot;Prefers arrow functions&quot;</td></tr><tr><td><strong>2. Project Knowledge</strong> (Project)</td><td><code>listMemories</code></td><td>Global knowledge of the current project</td><td>&quot;This project uses Clean Architecture&quot;, &quot;APIs are in src/api&quot;</td></tr><tr><td><strong>3. Relevant Memories</strong> (Relevant)</td><td><code>searchMemories</code></td><td>Past experiences related to your first sentence</td><td>You ask &quot;How to fix this bug&quot;, it finds similar fix records from the past</td></tr></tbody></table><hr><h2 id="what-is-injected" tabindex="-1">What is Injected? <a class="header-anchor" href="#what-is-injected" aria-label="Permalink to &quot;What is Injected?&quot;">​</a></h2><p>When you send your first message in OpenCode, the plugin silently inserts the following content into the System Prompt in the background.</p><details class="details custom-block"><summary>Click to view the actual structure of injected content</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>After seeing this information, the Agent behaves like a veteran employee who has worked on this project for a long time, rather than a new intern.</p><hr><h2 id="keyword-trigger-mechanism-nudge" tabindex="-1">Keyword Trigger Mechanism (Nudge) <a class="header-anchor" href="#keyword-trigger-mechanism-nudge" aria-label="Permalink to &quot;Keyword Trigger Mechanism (Nudge)&quot;">​</a></h2><p>In addition to the automatic injection at the start, you can &quot;wake up&quot; the memory function at any time during the conversation.</p><p>The plugin has a built-in <strong>Keyword Detector</strong>. As long as your message contains specific trigger words, the plugin sends an &quot;invisible hint&quot; (Nudge) to the Agent, forcing it to call the save tool.</p><h3 id="default-keywords" tabindex="-1">Default Keywords <a class="header-anchor" href="#default-keywords" aria-label="Permalink to &quot;Default Keywords&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (See source code configuration for more)</li></ul><h3 id="interaction-example" tabindex="-1">Interaction Example <a class="header-anchor" href="#interaction-example" aria-label="Permalink to &quot;Interaction Example&quot;">​</a></h3><p><strong>You type</strong>:</p><blockquote><p>The API response format has changed here, <strong>remember</strong> to use <code>data.result</code> instead of <code>data.payload</code> from now on.</p></blockquote><p><strong>Plugin detects &quot;remember&quot;</strong>:</p><blockquote><p>(Background injection hint): <code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Agent reacts</strong>:</p><blockquote><p>Understood. I will remember this change. <em>(Calls <code>supermemory.add</code> in the background to save memory)</em></p></blockquote><hr><h2 id="advanced-configuration" tabindex="-1">Advanced Configuration <a class="header-anchor" href="#advanced-configuration" aria-label="Permalink to &quot;Advanced Configuration&quot;">​</a></h2><p>You can adjust the injection behavior by modifying <code>~/.config/opencode/supermemory.jsonc</code>.</p><h3 id="common-configuration-options" tabindex="-1">Common Configuration Options <a class="header-anchor" href="#common-configuration-options" aria-label="Permalink to &quot;Common Configuration Options&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Whether to inject user profile (default true)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // How many project memories to inject each time (default 10)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Increasing this helps the Agent understand the project better but consumes more Tokens</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // How many user profile items to inject each time (default 5)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Custom trigger words (supports Regex)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;note this&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;save forever&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>After modifying the configuration, you need to restart OpenCode or reload the plugin for changes to take effect.</p></div><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="q-does-the-injected-information-consume-a-lot-of-tokens" tabindex="-1">Q: Does the injected information consume a lot of Tokens? <a class="header-anchor" href="#q-does-the-injected-information-consume-a-lot-of-tokens" aria-label="Permalink to &quot;Q: Does the injected information consume a lot of Tokens?&quot;">​</a></h3><p><strong>A</strong>: It consumes some, but it is usually manageable. Under the default configuration (10 project memories + 5 profile items), it takes up about 500-1000 Tokens. For the 200k context of modern large models (like Claude 3.5 Sonnet), this is a drop in the bucket.</p><h3 id="q-why-didn-t-it-react-when-i-said-remember" tabindex="-1">Q: Why didn&#39;t it react when I said &quot;remember&quot;? <a class="header-anchor" href="#q-why-didn-t-it-react-when-i-said-remember" aria-label="Permalink to &quot;Q: Why didn&#39;t it react when I said &quot;remember&quot;?&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>Check if the spelling is correct (Regex matching is supported).</li><li>Confirm if the API Key is configured correctly (it won&#39;t trigger if the plugin is not initialized).</li><li>The Agent might have decided to ignore it (although the plugin forces a hint, the Agent has the final say).</li></ol><h3 id="q-how-are-relevant-memories-found" tabindex="-1">Q: How are &quot;Relevant Memories&quot; found? <a class="header-anchor" href="#q-how-are-relevant-memories-found" aria-label="Permalink to &quot;Q: How are &quot;Relevant Memories&quot; found?&quot;">​</a></h3><p><strong>A</strong>: It performs a semantic search based on the <strong>content of your first message</strong>. If your first sentence is just &quot;Hi&quot;, it might not find any useful relevant memories, but &quot;Project Knowledge&quot; and &quot;User Profile&quot; will still be injected.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><ul><li><strong>Automatic Injection</strong> triggers only on the first message of the session.</li><li><strong>The 3D Model</strong> includes User Profile, Project Knowledge, and Relevant Memories.</li><li><strong>Keyword Trigger</strong> allows you to command the Agent to save memories at any time.</li><li>You can control the amount of injected information via the <strong>Configuration File</strong>.</li></ul><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><blockquote><p>Next, we will learn <strong><a href="./../tools/">Tool Set Details: Teaching Agents to Remember</a></strong>.</p><p>You will learn:</p><ul><li>How to manually use tools like <code>add</code>, <code>search</code>, etc.</li><li>How to view and delete incorrect memories.</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Injection Trigger Logic</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>Keyword Detection</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Prompt Formatting</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>Default Configuration</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>Key Functions</strong>:</p><ul><li><code>formatContextForPrompt()</code>: Assembles the <code>[SUPERMEMORY]</code> text block.</li><li><code>detectMemoryKeyword()</code>: Regex matches trigger words in user messages.</li></ul></details><h2 id="next-step-1" tabindex="-1">Next Step <a class="header-anchor" href="#next-step-1" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><blockquote><p>Next, we will learn <strong><a href="./../tools/">Tool Set Details: Teaching Agents to Remember</a></strong>.</p><p>You will learn:</p><ul><li>Master 5 core tool modes including <code>add</code>, <code>search</code>, <code>profile</code></li><li>How to manually intervene and correct Agent memories</li><li>Triggering memory saves using natural language</li></ul></blockquote>`,57)])])}const m=t(a,[["render",i]]);export{u as __pageData,m as default};
